    makeFrame("Finalização e retorno", "Finalize equilibrado e volte para a base.", [{ jogador_id: "A1", de: { x: 68, y: 34 }, para: { x: 76, y: 28 } }], [], [{ tipo: "movimento", de: { x: 68, y: 34 }, para: { x: 76, y: 28 }, rotulo: "base" }], ["A1"])
